figure.artwork:
Response = COSE_Sign1(
  protected: { 1 (alg): -7 (ES256) },
  unprotected: {},
  payload: {
    1 : 0x11,            / type /
    2 : challenge_nonce,  / echoed from challenge /
    3 : assurance         / 1=PRESENCE, 2=DEVICE /
  }
)

for i in 0..5:
  group[i] = BE_uint(digest[i*5 .. (i+1)*5]) mod 100000
output = sprintf("%05d %05d %05d %05d %05d %05d", group[0..5])
